Write a class that handles both Simple and Complex splits:

```java
package fan.summer.buildintool.excelsplitter;

import fan.summer.database.DatabaseInit;
import fan.summer.database.entity.excel.ComplexSplitConfigEntity;
import fan.summer.database.mapper.excel.ComplexSplitConfigMapper;
import org.apache.fesod.sheet.ExcelReader;
import org.apache.fesod.sheet.FesodSheet;
import org.apache.fesod.sheet.read.metadata.ReadSheet;
import org.apache.ibatis.session.SqlSession;
import org.apache.poi.ss.usermodel.*;
import org.apache.poi.xssf.usermodel.XSSFWorkbook;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.FileOutputStream;
import java.io.IOException;
import java.nio.file.Path;
import java.util.*;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.function.BiConsumer;
import java.util.stream.Collectors;

public class ExcelSplitter {

    private static final Logger log = LoggerFactory.getLogger(ExcelSplitter.class);

    public record SplitResult(int fileCount, List<Path> outputFiles) {}

    private final SplitConfig config;
    private final BiConsumer<Double, String> progress;

    public ExcelSplitter(SplitConfig config, BiConsumer<Double, String> progress) {
        this.config = config;
        this.progress = progress;
    }

    public SplitResult split() throws Exception {
        progress.accept(0.0, "准备中...");
        return switch (config.mode) {
            case SIMPLE  -> doSimpleSplit();
            case COMPLEX -> doComplexSplit();
        };
    }

    // ── Simple split ────────────────────────────────────────────

    private SplitResult doSimpleSplit() throws Exception {
        return switch (config.simpleMode) {
            case BY_SHEET  -> splitBySheet();
            case BY_COLUMN -> splitByColumn();
        };
    }

    private SplitResult splitBySheet() throws Exception {
        List<String> sheets = config.selectedSheets.isEmpty()
                ? new ArrayList<>(config.analysisResult.keySet())
                : config.selectedSheets;
        List<Path> outputs = new ArrayList<>();
        try (Workbook src = WorkbookFactory.create(config.sourceFile.toFile(), null, true)) {
            for (int i = 0; i < sheets.size(); i++) {
                String name = sheets.get(i);
                progress.accept((double) i / sheets.size(), "处理 Sheet: " + name);
                Sheet sheet = src.getSheet(name);
                if (sheet == null) continue;
                Path out = outputPath(sanitize(name));
                try (Workbook wb = new XSSFWorkbook();
                     FileOutputStream fos = new FileOutputStream(out.toFile())) {
                    copySheet(src, sheet, wb);
                    wb.write(fos);
                }
                outputs.add(out);
            }
        }
        progress.accept(1.0, "完成");
        return new SplitResult(outputs.size(), outputs);
    }

    private SplitResult splitByColumn() throws Exception {
        Map<Integer, String> headerMap = config.analysisResult.get(config.selectedSheet);
        if (headerMap == null) throw new IllegalStateException("未找到 Sheet: " + config.selectedSheet);
        int colIdx = config.selectedColumnIndex;
        List<Path> outputs = new ArrayList<>();
        NoModelDataListener listener = new NoModelDataListener();
        try (ExcelReader reader = FesodSheet.read(config.sourceFile.toFile()).build()) {
            ReadSheet rs = FesodSheet.readSheet(config.selectedSheet)
                    .registerReadListener(listener).build();
            reader.read(rs);
        }
        List<Map<Integer, Object>> rows = listener.getCachedDataList();
        Map<Object, List<Map<Integer, Object>>> groups = rows.stream()
                .collect(Collectors.groupingBy(row -> ExcelUtil.normalizeOrInvalid(row.getOrDefault(colIdx, null))));
        int total = groups.size();
        AtomicInteger idx = new AtomicInteger(0);
        for (Map.Entry<Object, List<Map<Integer, Object>>> e : groups.entrySet()) {
            String key = e.getKey().toString();
            progress.accept((double) idx.get() / total, "写入: " + key);
            Path out = outputPath(sanitize(key));
            FesodSheet.write(out.toFile())
                    .sheet(config.selectedSheet)
                    .head(buildHeaders(headerMap))
                    .doWrite(buildRows(headerMap, e.getValue()));
            outputs.add(out);
            idx.incrementAndGet();
        }
        progress.accept(1.0, "完成");
        return new SplitResult(outputs.size(), outputs);
    }

    // ── Complex split (mirrors ExcelSplitWorker.doComplexSplit) ────

    private SplitResult doComplexSplit() throws Exception {
        List<Path> outputs = new ArrayList<>();
        try (SqlSession session = DatabaseInit.getSqlSession()) {
            ComplexSplitConfigMapper mapper = session.getMapper(ComplexSplitConfigMapper.class);
            List<ComplexSplitConfigEntity> configs = mapper.selectAllByTaskId(config.taskId);
            if (configs == null || configs.isEmpty())
                throw new IllegalStateException("复杂拆分配置为空，请先添加配置");

            List<ComplexSplitConfigEntity> normal = new ArrayList<>();
            List<ComplexSplitConfigEntity> copyAll = new ArrayList<>();
            for (ComplexSplitConfigEntity cfg : configs) {
                if (cfg.getHeaderIndex() != null && cfg.getColumnIndex() != null
                        && cfg.getHeaderIndex() == -1 && cfg.getColumnIndex() == -1) {
                    copyAll.add(cfg);
                } else {
                    normal.add(cfg);
                }
            }

            // Count total groups for progress
            int totalGroups = 0;
            for (ComplexSplitConfigEntity cfg : normal) {
                NoModelDataListener listener = new NoModelDataListener();
                try (ExcelReader reader = FesodSheet.read(config.sourceFile.toFile()).build()) {
                    ReadSheet rs = FesodSheet.readSheet(cfg.getSheetName())
                            .headRowNumber(cfg.getHeaderIndex())
                            .registerReadListener(listener).build();
                    reader.read(rs);
                }
                totalGroups += listener.getCachedDataList().stream()
                        .collect(Collectors.groupingBy(row ->
                                ExcelUtil.normalizeOrInvalid(row.getOrDefault(cfg.getColumnIndex() - 1, null))))
                        .size();
            }
            int totalOps = totalGroups + (copyAll.isEmpty() ? 0 : copyAll.size() * totalGroups);
            AtomicInteger done = new AtomicInteger(0);

            // Process normal configs
            for (ComplexSplitConfigEntity cfg : normal) {
                NoModelDataListener listener = new NoModelDataListener();
                try (ExcelReader reader = FesodSheet.read(config.sourceFile.toFile()).build()) {
                    ReadSheet rs = FesodSheet.readSheet(cfg.getSheetName())
                            .headRowNumber(cfg.getHeaderIndex())
                            .registerReadListener(listener).build();
                    reader.read(rs);
                }
                Map<Object, List<Map<Integer, Object>>> groups = listener.getCachedDataList()
                        .stream().collect(Collectors.groupingBy(row ->
                                ExcelUtil.normalizeOrInvalid(row.getOrDefault(cfg.getColumnIndex() - 1, null))));
                for (Map.Entry<Object, List<Map<Integer, Object>>> e : groups.entrySet()) {
                    String key = e.getKey().toString();
                    String outName = FileNameUtil.getFileName(config.sourceFile.getFileName().toString()) + "_" + key + ".xlsx";
                    Path outPath = config.outputDir.resolve(outName);
                    progress.accept((double) done.get() / totalOps, "写入: " + outName);
                    ExcelUtil.appendSheet(config.sourceFile.toString(), outPath.toString(),
                            cfg.getSheetName(), cfg.getHeaderIndex() - 1);
                    ExcelUtil.appendDataRowsByPoi(config.sourceFile.toString(), outPath.toString(),
                            cfg.getSheetName(), cfg.getHeaderIndex(), e.getValue());
                    if (!outputs.contains(outPath)) outputs.add(outPath);
                    done.incrementAndGet();
                }
            }

            // Copy-all configs
            if (!copyAll.isEmpty()) {
                java.io.File[] outFiles = config.outputDir.toFile()
                        .listFiles((d, n) -> n.endsWith(".xlsx"));
                if (outFiles != null) {
                    for (ComplexSplitConfigEntity cfg : copyAll) {
                        for (java.io.File f : outFiles) {
                            try {
                                ExcelUtil.copyEntireSheet(config.sourceFile.toString(),
                                        f.getAbsolutePath(), cfg.getSheetName());
                            } catch (IOException ex) {
                                log.warn("copyEntireSheet failed for {}: {}", f.getName(), ex.getMessage());
                            }
                            done.incrementAndGet();
                            progress.accept((double) done.get() / totalOps, "追加 Sheet: " + cfg.getSheetName());
                        }
                    }
                }
            }
        }
        progress.accept(1.0, "完成");
        return new SplitResult(outputs.size(), outputs);
    }

    // ── Sheet / row copy helpers (for BY_SHEET simple split) ────

    private void copySheet(Workbook srcWb, Sheet src, Workbook destWb) {
        Sheet dest = destWb.createSheet(src.getSheetName());
        for (int r = src.getFirstRowNum(); r <= src.getLastRowNum(); r++) {
            Row srcRow = src.getRow(r);
            if (srcRow == null) continue;
            copyRow(srcWb, destWb, srcRow, dest.createRow(r));
        }
    }

    private void copyRow(Workbook srcWb, Workbook destWb, Row src, Row dest) {
        dest.setHeight(src.getHeight());
        for (int c = src.getFirstCellNum(); c < src.getLastCellNum(); c++) {
            Cell srcCell = src.getCell(c);
            Cell destCell = dest.createCell(c);
            if (srcCell == null) continue;
            copyCellValue(srcCell, destCell);
        }
    }

    private void copyCellValue(Cell src, Cell dest) {
        switch (src.getCellType()) {
            case STRING  -> dest.setCellValue(src.getStringCellValue());
            case NUMERIC -> {
                if (DateUtil.isCellDateFormatted(src)) dest.setCellValue(src.getDateCellValue());
                else dest.setCellValue(src.getNumericCellValue());
            }
            case BOOLEAN -> dest.setCellValue(src.getBooleanCellValue());
            case FORMULA -> {
                switch (src.getCachedFormulaResultType()) {
                    case NUMERIC  -> dest.setCellValue(src.getNumericCellValue());
                    case STRING   -> dest.setCellValue(src.getStringCellValue());
                    case BOOLEAN  -> dest.setCellValue(src.getBooleanCellValue());
                    default       -> dest.setCellFormula(src.getCellFormula());
                }
            }
            case BLANK -> dest.setBlank();
            default -> dest.setCellValue(src.toString());
        }
    }

    // ── Fesod format helpers ─────────────────────────────────────

    private static List<List<String>> buildHeaders(Map<Integer, String> headMap) {
        List<List<String>> headers = new ArrayList<>();
        new TreeMap<>(headMap).forEach((idx, name) -> headers.add(Collections.singletonList(name)));
        return headers;
    }

    private static List<List<Object>> buildRows(Map<Integer, String> headMap, List<Map<Integer, Object>> dataList) {
        List<Integer> sorted = new ArrayList<>(new TreeMap<>(headMap).keySet());
        List<List<Object>> rows = new ArrayList<>();
        for (Map<Integer, Object> row : dataList) {
            List<Object> r = new ArrayList<>();
            for (Integer k : sorted) r.add(row.getOrDefault(k, ""));
            rows.add(r);
        }
        return rows;
    }

    private String sanitize(String name) {
        return name.replaceAll("[\\\\/:*?\"<>|]", "_").trim();
    }

    private Path outputPath(String name) {
        return config.outputDir.resolve(name + ".xlsx");
    }
}
```

### 9. ExcelSplitterPlugin.java
