1	package fan.summer.buildintool.excelsplitter;
2	
3	import org.apache.poi.ss.usermodel.*;
4	import org.apache.poi.xssf.usermodel.XSSFWorkbook;
5	
6	import java.io.FileOutputStream;
7	import java.nio.file.*;
8	import java.util.*;
9	import java.util.function.BiConsumer;
10	
11	/**
12	 * Excel split core logic.
13	 * Does not depend on JavaFX, can be safely called in background threads.
14	 *
15	 * Progress callback: BiConsumer<current progress (0~1), status description>
16	 */
17	public class ExcelSplitter {
18	
19	    public record SplitResult(int fileCount, List<Path> outputFiles) {}
20	
21	    private final SplitConfig           config;
22	    private final BiConsumer<Double, String> progress;
23	
24	    public ExcelSplitter(SplitConfig config, BiConsumer<Double, String> progress) {
25	        this.config   = config;
26	        this.progress = progress;
27	    }
28	
29	    public SplitResult split() throws Exception {
30	        progress.accept(0.0, "Reading file…");
31	
32	        try (Workbook src = WorkbookFactory.create(config.sourceFile.toFile(), null, true)) {
33	            return switch (config.mode) {
34	                case BY_SHEET      -> splitBySheet(src);
35	                case BY_COLUMN     -> splitByColumn(src);
36	                case BY_ROW_COUNT  -> splitByRowCount(src);
37	            };
38	        }
39	    }
40	
41	    // ── Split by sheet ─────────────────────────────────────
42	
43	    private SplitResult splitBySheet(Workbook src) throws Exception {
44	        List<String> targets = config.selectedSheets != null
45	            ? config.selectedSheets
46	            : config.sheetNames;
47	
48	        List<Path> outputs = new ArrayList<>();
49	        for (int i = 0; i < targets.size(); i++) {
50	            String name = targets.get(i);
51	            progress.accept((double) i / targets.size(), "Processing sheet：" + name);
52	
53	            Sheet sheet = src.getSheet(name);
54	            if (sheet == null) continue;
55	
56	            Path out = outputPath(sanitize(name));
57	            try (Workbook wb = new XSSFWorkbook();
58	                 FileOutputStream fos = new FileOutputStream(out.toFile())) {
59	                copySheet(src, sheet, wb);
60	                wb.write(fos);
61	            }
62	            outputs.add(out);
63	        }
64	        progress.accept(1.0, "Done");
65	        return new SplitResult(outputs.size(), outputs);
66	    }
67	
68	    // ── Split by column value ────────────────────────────────────────
69	
70	    private SplitResult splitByColumn(Workbook src) throws Exception {
71	        Sheet sheet = src.getSheetAt(0);
72	        Row header  = config.keepHeader ? sheet.getRow(sheet.getFirstRowNum()) : null;
73	        int  colIdx = config.splitColumnIndex;
74	
75	        // Group rows by column value
76	        Map<String, List<Row>> groups = new LinkedHashMap<>();
77	        for (int r = sheet.getFirstRowNum() + (config.keepHeader ? 1 : 0);
78	             r <= sheet.getLastRowNum(); r++) {
79	            Row row = sheet.getRow(r);
80	            if (row == null) continue;
81	            String key = cellValue(row.getCell(colIdx));
82	            groups.computeIfAbsent(key, k -> new ArrayList<>()).add(row);
83	        }
84	
85	        List<Path> outputs = new ArrayList<>();
86	        int i = 0;
87	        for (Map.Entry<String, List<Row>> entry : groups.entrySet()) {
88	            progress.accept((double) i / groups.size(), "Writing：" + entry.getKey());
89	            Path out = outputPath(sanitize(entry.getKey()));
90	            writeRows(src, sheet, header, entry.getValue(), out);
91	            outputs.add(out);
92	            i++;
93	        }
94	        progress.accept(1.0, "Done");
95	        return new SplitResult(outputs.size(), outputs);
96	    }
97	
98	    // ── Split by row count ────────────────────────────────────────
99	
100	    private SplitResult splitByRowCount(Workbook src) throws Exception {
101	        Sheet sheet   = src.getSheetAt(0);
102	        Row   header  = config.keepHeader ? sheet.getRow(sheet.getFirstRowNum()) : null;
103	        int   start   = sheet.getFirstRowNum() + (config.keepHeader ? 1 : 0);
104	        int   total   = sheet.getLastRowNum() - start + 1;
105	        int   batchSz = config.rowsPerFile;
106	
107	        List<Path> outputs = new ArrayList<>();
108	        int part = 1;
109	        for (int r = start; r <= sheet.getLastRowNum(); r += batchSz) {
110	            progress.accept((double)(r - start) / total, "Writing part " + part + "…");
111	            List<Row> batch = new ArrayList<>();
112	            for (int rr = r; rr < r + batchSz && rr <= sheet.getLastRowNum(); rr++) {
113	                Row row = sheet.getRow(rr);
114	                if (row != null) batch.add(row);
115	            }
116	            Path out = outputPath("part_" + String.format("%03d", part));
117	            writeRows(src, sheet, header, batch, out);
118	            outputs.add(out);
119	            part++;
120	        }
121	        progress.accept(1.0, "Done");
122	        return new SplitResult(outputs.size(), outputs);
123	    }
124	
125	    // ── Helper: write rows ─────────────────────────────────────
126	
127	    private void writeRows(Workbook src, Sheet srcSheet,
128	                           Row header, List<Row> rows, Path dest) throws Exception {
129	        try (Workbook wb = new XSSFWorkbook();
130	             FileOutputStream fos = new FileOutputStream(dest.toFile())) {
131	            Sheet out = wb.createSheet(srcSheet.getSheetName());
132	            int rowNum = 0;
133	            if (header != null) {
134	                copyRow(src, wb, header, out.createRow(rowNum++));
135	            }
136	            for (Row src_row : rows) {
137	                copyRow(src, wb, src_row, out.createRow(rowNum++));
138	            }
139	            // Auto column width (only first 50 columns to avoid performance issues)
140	            int cols = Math.min(srcSheet.getRow(srcSheet.getFirstRowNum()) != null
141	                ? srcSheet.getRow(srcSheet.getFirstRowNum()).getLastCellNum() : 10, 50);
142	            for (int c = 0; c < cols; c++) out.autoSizeColumn(c);
143	            wb.write(fos);
144	        }
145	    }
146	
147	    // ── Helper: sheet copy ─────────────────────────────────
148	
149	    private void copySheet(Workbook srcWb, Sheet src, Workbook destWb) {
150	        Sheet dest = destWb.createSheet(src.getSheetName());
151	        for (int r = src.getFirstRowNum(); r <= src.getLastRowNum(); r++) {
152	            Row srcRow = src.getRow(r);
153	            if (srcRow == null) continue;
154	            copyRow(srcWb, destWb, srcRow, dest.createRow(r));
155	        }
156	        // Column width
157	        int cols = src.getRow(src.getFirstRowNum()) != null
158	            ? src.getRow(src.getFirstRowNum()).getLastCellNum() : 0;
159	        for (int c = 0; c < Math.min(cols, 50); c++) dest.autoSizeColumn(c);
160	    }
161	
162	    private void copyRow(Workbook srcWb, Workbook destWb, Row src, Row dest) {
163	        dest.setHeight(src.getHeight());
164	        for (int c = src.getFirstCellNum(); c < src.getLastCellNum(); c++) {
165	            Cell srcCell  = src.getCell(c);
166	            Cell destCell = dest.createCell(c);
167	            if (srcCell == null) continue;
168	            copyCellValue(srcCell, destCell);
169	        }
170	    }
171	
172	    private void copyCellValue(Cell src, Cell dest) {
173	        switch (src.getCellType()) {
174	            case STRING  -> dest.setCellValue(src.getStringCellValue());
175	            case NUMERIC -> {
176	                if (DateUtil.isCellDateFormatted(src))
177	                    dest.setCellValue(src.getDateCellValue());
178	                else
179	                    dest.setCellValue(src.getNumericCellValue());
180	            }
181	            case BOOLEAN -> dest.setCellValue(src.getBooleanCellValue());
182	            case FORMULA -> {
183	                switch (src.getCachedFormulaResultType()) {
184	                    case NUMERIC  -> dest.setCellValue(src.getNumericCellValue());
185	                    case STRING   -> dest.setCellValue(src.getStringCellValue());
186	                    case BOOLEAN  -> dest.setCellValue(src.getBooleanCellValue());
187	                    default       -> dest.setCellFormula(src.getCellFormula());
188	                }
189	            }
190	            case BLANK   -> dest.setBlank();
