39	        // Reset wizard on each entry for easy re-split
40	        view = null;
41	    }
42	
43	    @Override
44	    public Node createView() {
45	        if (view != null) return view;
46	        config = new SplitConfig();
47	        view   = buildWizardView();
48	        return view;
49	    }
50	
51	    // ════════════════════════════════════════════════════
52	    // Wizard build
53	    // ════════════════════════════════════════════════════
54	
55	    private Node buildWizardView() {
56	        StepWizard wizard = new StepWizard();
57	
58	        // ── Step 1: Select file ─────────────────────────────
59	        Step1View step1 = new Step1View(config);
60	        wizard.addStep("Select file", step1,
61	            () -> config.sourceFile != null && Files.exists(config.sourceFile)
62	        );
63	
64	        // ── Step 2: Split mode ─────────────────────────────
65	        Step2View step2 = new Step2View(config);
66	        wizard.addStep("Split mode", step2, () -> {
67	            if (config.mode == SplitConfig.SplitMode.BY_COLUMN
68	                    && (config.splitColumn == null || config.splitColumn.isBlank())) {
69	                return false;
70	            }
71	            if (config.mode == SplitConfig.SplitMode.BY_ROW_COUNT
72	                    && config.rowsPerFile <= 0) {
73	                return false;
74	            }
75	            return true;
76	        });
77	
78	        // ── Step 3: Output settings ─────────────────────────────
79	        Step3View step3 = new Step3View(config);
80	        wizard.addStep("Output settings", step3,
81	            () -> config.outputDir != null && Files.isDirectory(config.outputDir)
82	        );
83	
84	        // ── Step 4: Execute split ─────────────────────────────
85	        Step4View step4 = new Step4View(config);
86	        wizard.addStep("Execute split", step4, () -> true);
87	
88	        // Wire step-change callbacks
89	        wizard.setOnStepChanged((from, to, total) -> {
90	            // On entering step 2: refresh the column selector (file is already selected)
91	            if (to == 1) step2.refresh(config);
