93	            if (to == 3) step4.startSplit();
94	        });
95	
96	        // Second listener overwrites the first — kept intentionally for step 4 trigger
97	        wizard.setOnStepChanged((from, to, total) -> {
98	            if (to == 1) step2.refresh(config);
99	            if (to == 3) step4.startSplit();
100	        });
101	
102	        // Wrap in a VBox to add outer padding
103	        VBox root = new VBox(wizard);
104	        VBox.setVgrow(wizard, Priority.ALWAYS);
105	        root.setPadding(new Insets(24));
106	        root.setStyle("-fx-background-color: transparent;");
