109	
110	    // ════════════════════════════════════════════════════
111	    // Step 1: Select source file
112	    // ════════════════════════════════════════════════════
113	
114	    static class Step1View extends VBox {
115	        private final SplitConfig config;
116	        private final Label       fileLabel;
117	        private final Label       previewLabel;
118	
119	        Step1View(SplitConfig config) {
120	            this.config = config;
121	            setSpacing(16);
122	            setStyle("-fx-background-color: transparent;");
123	
124	            Label title = sectionTitle("Select Excel file to split");
125	
126	            fileLabel = new Label("No file selected");
127	            fileLabel.setStyle(
128	                "-fx-text-fill: rgba(255,255,255,0.40); -fx-font-size: 13px;" +
129	                "-fx-font-family: 'SF Mono','Consolas',monospace;"
130	            );
131	            fileLabel.setWrapText(true);
132	
133	            Button pickBtn = glassBtn("📂  Select file", true);
134	            pickBtn.setOnAction(e -> pickFile());
135	
136	            // Drop zone
137	            VBox dropZone = new VBox(12, pickBtn, fileLabel);
138	            dropZone.setAlignment(Pos.CENTER);
139	            dropZone.setPrefHeight(140);
140	            dropZone.setStyle(
141	                "-fx-background-color: rgba(255,255,255,0.03);" +
142	                "-fx-border-color: rgba(255,255,255,0.12);" +
143	                "-fx-border-width: 1; -fx-border-style: dashed;" +
144	                "-fx-border-radius: 12; -fx-background-radius: 12;"
145	            );
146	
147	            // Drag and drop support
