149	                if (e.getDragboard().hasFiles()) {
150	                    e.acceptTransferModes(javafx.scene.input.TransferMode.COPY);
151	                    dropZone.setStyle(dropZone.getStyle()
152	                        .replace("rgba(255,255,255,0.03)", "rgba(91,140,247,0.10)")
153	                        .replace("rgba(255,255,255,0.12)", "rgba(91,140,247,0.40)"));
154	                }
155	                e.consume();
156	            });
157	            dropZone.setOnDragExited(e ->
158	                dropZone.setStyle(dropZone.getStyle()
159	                    .replace("rgba(91,140,247,0.10)", "rgba(255,255,255,0.03)")
160	                    .replace("rgba(91,140,247,0.40)", "rgba(255,255,255,0.12)"))
161	            );
162	            dropZone.setOnDragDropped(e -> {
163	                List<File> files = e.getDragboard().getFiles();
164	                if (!files.isEmpty()) loadFile(files.get(0).toPath());
165	                e.setDropCompleted(true);
