167	            });
168	
169	            previewLabel = new Label();
170	            previewLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.55); -fx-font-size: 12px;");
171	            previewLabel.setWrapText(true);
172	
173	            getChildren().addAll(title, dropZone, previewLabel);
174	        }
175	
176	        private void pickFile() {
177	            FileChooser fc = new FileChooser();
178	            fc.setTitle("Select Excel file");
179	            fc.getExtensionFilters().add(
180	                new FileChooser.ExtensionFilter("Excel files", "*.xlsx", "*.xls", "*.xlsm")
181	            );
