186	        private void loadFile(Path path) {
187	            config.sourceFile = path;
188	            fileLabel.setText(path.getFileName().toString());
189	            fileLabel.setStyle(fileLabel.getStyle()
190	                .replace("rgba(255,255,255,0.40)", "rgba(255,255,255,0.88)"));
191	
192	            // Read sheet names
193	            try (Workbook wb = WorkbookFactory.create(path.toFile(), null, true)) {
194	                List<String> names = new ArrayList<>();
195	                for (int i = 0; i < wb.getNumberOfSheets(); i++)
196	                    names.add(wb.getSheetName(i));
197	                config.sheetNames      = names;
198	                config.selectedSheets  = new ArrayList<>(names);
199	                previewLabel.setText("✓ Contains " + names.size() + "  sheets：" +
200	                    names.stream().limit(5).collect(Collectors.joining(", ")) +
201	                    (names.size() > 5 ? " …" : ""));
