221	        // BY_SHEET control
222	        private ListView<String> sheetList;
223	
224	        Step2View(SplitConfig config) {
225	            this.config = config;
226	            setSpacing(16);
227	            setStyle("-fx-background-color: transparent;");
228	            build();
229	        }
230	
231	        private void build() {
232	            Label title = sectionTitle("Select split mode");
233	
234	            // Three radio-button cards
235	            ToggleGroup group = new ToggleGroup();
236	            VBox modeCards = new VBox(8,
237	                modeCard(group, SplitConfig.SplitMode.BY_SHEET,
238	                    "⊞  Split by sheet", "Each sheet outputs one independent file"),
239	                modeCard(group, SplitConfig.SplitMode.BY_COLUMN,
240	                    "🔤  Split by column value",  "Group by different values in a column, one file per group"),
241	                modeCard(group, SplitConfig.SplitMode.BY_ROW_COUNT,
242	                    "📏  Split by row count",  "Output one file every N rows")
243	            );
244	
245	            // Default select first
246	            ((RadioButton) modeCards.getChildren().get(0)
247	                .lookup(".radio-button") != null
248	                ? modeCards.getChildren().get(0)
249	                : modeCards.getChildren().get(0))
250	                .getClass(); // Trigger once to ensure initialization
251	
252	            // Select first Toggle
253	            group.getToggles().get(0).setSelected(true);
254	            config.mode = SplitConfig.SplitMode.BY_SHEET;
255	
256	            detailPane = new VBox();
257	            detailPane.setStyle("-fx-background-color: transparent;");
258	
259	            group.selectedToggleProperty().addListener((obs, o, n) -> {
