268	        }
269	
270	        /** Refresh dynamic content (column list etc.) when the source file changes */
271	        void refresh(SplitConfig config) {
272	            refreshDetail();
273	        }
274	
275	        private void refreshDetail() {
276	            detailPane.getChildren().clear();
277	            detailPane.setPadding(new Insets(4, 0, 0, 0));
278	
279	            switch (config.mode) {
280	                case BY_SHEET -> {
281	                    if (config.sheetNames == null || config.sheetNames.isEmpty()) return;
282	                    sheetList = new ListView<>();
283	                    sheetList.getItems().addAll(config.sheetNames);
284	                    sheetList.getSelectionModel().setSelectionMode(SelectionMode.MULTIPLE);
285	                    sheetList.getSelectionModel().selectAll();
286	                    sheetList.setPrefHeight(Math.min(config.sheetNames.size() * 32 + 8, 160));
287	                    sheetList.setStyle(
288	                        "-fx-background-color: rgba(255,255,255,0.04);" +
289	                        "-fx-border-color: rgba(255,255,255,0.10); -fx-border-radius: 8;" +
290	                        "-fx-background-radius: 8; -fx-text-fill: white;"
291	                    );
292	                    sheetList.getSelectionModel().selectedItemProperty().addListener((o, ov, nv) ->
293	                        config.selectedSheets = new ArrayList<>(
294	                            sheetList.getSelectionModel().getSelectedItems())
295	                    );
296	                    detailPane.getChildren().addAll(
297	                        subLabel("Select sheets to export (multiple allowed)"), sheetList
298	                    );
299	                }
300	                case BY_COLUMN -> {
301	                    columnCombo = new ComboBox<>();
302	                    columnCombo.setPromptText("Column to split by...…");
303	                    columnCombo.setMaxWidth(Double.MAX_VALUE);
304	                    columnCombo.setStyle(comboStyle());
305	
306	                    // Read first row header from file
307	                    if (config.sourceFile != null) {
308	                        try (Workbook wb = WorkbookFactory.create(
309	                                config.sourceFile.toFile(), null, true)) {
310	                            Sheet s = wb.getSheetAt(0);
311	                            Row header = s.getRow(s.getFirstRowNum());
312	                            if (header != null) {
313	                                for (int c = header.getFirstCellNum();
314	                                     c < header.getLastCellNum(); c++) {
315	                                    Cell cell = header.getCell(c);
316	                                    if (cell != null) {
317	                                        String val = cell.toString().trim();
318	                                        if (!val.isEmpty()) {
319	                                            columnCombo.getItems().add(val);
320	                                        }
321	                                    }
322	                                }
323	                            }
324	                        } catch (Exception ex) {
325	                            columnCombo.getItems().add("（Read failed：" + ex.getMessage() + "）");
326	                        }
327	                    }
328	
329	                    columnCombo.valueProperty().addListener((o, ov, nv) -> {
330	                        config.splitColumn = nv;
331	                        config.splitColumnIndex = columnCombo.getItems().indexOf(nv);
332	                    });
333	
334	                    detailPane.getChildren().addAll(subLabel("Which column to group by"), columnCombo);
335	                }
336	                case BY_ROW_COUNT -> {
337	                    rowSpinner = new Spinner<>(1, 1_000_000, 1000, 100);
338	                    rowSpinner.setEditable(true);
339	                    rowSpinner.setMaxWidth(Double.MAX_VALUE);
340	                    rowSpinner.setStyle(
341	                        "-fx-background-color: rgba(255,255,255,0.06);" +
342	                        "-fx-border-color: rgba(255,255,255,0.12); -fx-border-radius: 8;"
343	                    );
344	                    rowSpinner.valueProperty().addListener((o, ov, nv) ->
345	                        config.rowsPerFile = nv);
346	                    config.rowsPerFile = 1000;
347	
348	                    detailPane.getChildren().addAll(subLabel("Max rows per file"), rowSpinner);
349	                }
350	            }
351	        }
352	
353	        private HBox modeCard(ToggleGroup group, SplitConfig.SplitMode mode,
354	                              String label, String desc) {
355	            RadioButton rb = new RadioButton();
356	            rb.setToggleGroup(group);
357	            rb.setUserData(mode);
358	            rb.setStyle("-fx-text-fill: transparent;");
359	
360	            Label mainL = new Label(label);
361	            mainL.setStyle("-fx-text-fill: rgba(255,255,255,0.88); -fx-font-size: 13px; -fx-font-weight: 500;");
362	            Label descL = new Label(desc);
363	            descL.setStyle("-fx-text-fill: rgba(255,255,255,0.40); -fx-font-size: 11px;");
364	
365	            VBox text = new VBox(2, mainL, descL);
366	            HBox.setHgrow(text, Priority.ALWAYS);
367	            HBox card = new HBox(10, rb, text);
368	            card.setAlignment(Pos.CENTER_LEFT);
369	            card.setPadding(new Insets(12, 16, 12, 16));
370	            card.setStyle(
371	                "-fx-background-color: rgba(255,255,255,0.04);" +
372	                "-fx-border-color: rgba(255,255,255,0.10); -fx-border-width: 1;" +
373	                "-fx-border-radius: 10; -fx-background-radius: 10; -fx-cursor: hand;"
374	            );
375	            card.setOnMouseClicked(e -> rb.setSelected(true));
376	
377	            rb.selectedProperty().addListener((o, ov, nv) -> {
378	                if (nv) {
379	                    card.setStyle(card.getStyle()
380	                        .replace("rgba(255,255,255,0.04)", "rgba(91,140,247,0.10)")
381	                        .replace("rgba(255,255,255,0.10)", "rgba(91,140,247,0.35)"));
382	                } else {
383	                    card.setStyle(card.getStyle()
384	                        .replace("rgba(91,140,247,0.10)", "rgba(255,255,255,0.04)")
385	                        .replace("rgba(91,140,247,0.35)", "rgba(255,255,255,0.10)"));
386	                }
387	            });
388	
389	            return card;
390	        }
391	    }
392	
393	    // ════════════════════════════════════════════════════
394	    // Step 3: Output settings
395	    // ════════════════════════════════════════════════════
396	
397	    static class Step3View extends VBox {
398	        private final SplitConfig config;
399	        private final Label       dirLabel;
400	
401	        Step3View(SplitConfig config) {
402	            this.config = config;
403	            setSpacing(16);
404	            setStyle("-fx-background-color: transparent;");
405	
406	            Label title = sectionTitle("Output settings");
407	
408	            dirLabel = new Label("No directory selected");
409	            dirLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.40); -fx-font-size: 12px;" +
410	                              "-fx-font-family: 'SF Mono','Consolas',monospace;");
411	            dirLabel.setWrapText(true);
412	
413	            Button dirBtn = glassBtn("📁  Select output directory", true);
414	            dirBtn.setOnAction(e -> {
415	                DirectoryChooser dc = new DirectoryChooser();
416	                dc.setTitle("Select output directory");
417	                // Default to source file directory
418	                if (config.sourceFile != null)
419	                    dc.setInitialDirectory(config.sourceFile.getParent().toFile());
420	                File dir = dc.showDialog(getScene() != null ? getScene().getWindow() : null);
421	                if (dir != null) {
422	                    config.outputDir = dir.toPath();
423	                    dirLabel.setText(dir.getAbsolutePath());
424	                    dirLabel.setStyle(dirLabel.getStyle()
425	                        .replace("rgba(255,255,255,0.40)", "rgba(255,255,255,0.88)"));
426	                }
427	            });
428	
429	            // File name prefix
430	            Label prefixLabel = subLabel("Output file name prefix (optional)");
431	            TextField prefixField = new TextField();
432	            prefixField.setPromptText("example: output → output_Sheet1.xlsx");
433	            prefixField.setStyle(fieldStyle());
434	            prefixField.textProperty().addListener((o, ov, nv) -> config.filePrefix = nv);
435	
436	            // Keep header
437	            CheckBox keepHeader = new CheckBox("Keep header row when splitting by column or row count");
438	            keepHeader.setSelected(true);
439	            keepHeader.setStyle("-fx-text-fill: rgba(255,255,255,0.75); -fx-font-size: 13px;");
440	            keepHeader.selectedProperty().addListener((o, ov, nv) -> config.keepHeader = nv);
441	
442	            getChildren().addAll(
443	                title,
444	                dirBtn, dirLabel,
445	                new Separator() {{ setStyle("-fx-border-color: rgba(255,255,255,0.08);"); }},
446	                prefixLabel, prefixField,
447	                keepHeader
448	            );
449	        }
450	    }
451	
452	    // ════════════════════════════════════════════════════
453	    // Step 4: Execute split and show results
454	    // ════════════════════════════════════════════════════
455	
456	    static class Step4View extends VBox {
457	        private final SplitConfig config;
458	        private final ProgressBar  progressBar;
459	        private final Label        progressLabel;
460	        private final VBox         resultBox;
461	        private boolean started = false;
462	
463	        Step4View(SplitConfig config) {
464	            this.config = config;
465	            setSpacing(16);
466	            setStyle("-fx-background-color: transparent;");
467	
468	            Label title = sectionTitle("Splitting...…");
469	
470	            progressBar = new ProgressBar(0);
471	            progressBar.setMaxWidth(Double.MAX_VALUE);
472	            progressBar.setPrefHeight(6);
473	            progressBar.setStyle("-fx-accent: #5b8cf7; -fx-background-radius: 3; -fx-background-color: rgba(255,255,255,0.08);");
474	
475	            progressLabel = new Label("Preparing...…");
476	            progressLabel.setStyle("-fx-text-fill: rgba(255,255,255,0.55); -fx-font-size: 12px;");
477	
478	            resultBox = new VBox(8);
479	            resultBox.setStyle("-fx-background-color: transparent;");
480	
481	            getChildren().addAll(title, progressBar, progressLabel, resultBox);
482	        }
483	
484	        void startSplit() {
485	            if (started) return;
486	            started = true;
487	            resultBox.getChildren().clear();
488	
489	            Task<ExcelSplitter.SplitResult> task = new Task<>() {
490	                @Override
491	                protected ExcelSplitter.SplitResult call() throws Exception {
492	                    ExcelSplitter splitter = new ExcelSplitter(config, (pct, msg) ->
493	                        Platform.runLater(() -> {
494	                            progressBar.setProgress(pct);
495	                            progressLabel.setText(msg);
496	                        })
497	                    );
498	                    return splitter.split();
499	                }
500	            };
501	
502	            task.setOnSucceeded(e -> showSuccess(task.getValue()));
503	            task.setOnFailed(e  -> showError(task.getException()));
504	
505	            Thread t = new Thread(task);
506	            t.setDaemon(true);
507	            t.start();
508	        }
509	
510	        private void showSuccess(ExcelSplitter.SplitResult result) {
511	            progressBar.setProgress(1.0);
512	            progressBar.setStyle(progressBar.getStyle().replace("#5b8cf7", "#4cd97b"));
513	            progressLabel.setText("✓ Split complete, output " + result.fileCount() + "  files");
514	
515	            resultBox.getChildren().add(subLabel("Output files"));
516	            for (Path p : result.outputFiles()) {
517	                HBox row = new HBox(10);
518	                row.setAlignment(Pos.CENTER_LEFT);
519	                row.setPadding(new Insets(8, 12, 8, 12));
520	                row.setStyle(
521	                    "-fx-background-color: rgba(76,217,123,0.06);" +
522	                    "-fx-border-color: rgba(76,217,123,0.15);" +
523	                    "-fx-border-width: 1; -fx-border-radius: 8; -fx-background-radius: 8;"
524	                );
525	
526	                Label icon = new Label("📄");
527	                Label name = new Label(p.getFileName().toString());
528	                name.setStyle("-fx-text-fill: rgba(255,255,255,0.85); -fx-font-size: 12px;" +
529	                              "-fx-font-family: 'SF Mono','Consolas',monospace;");
530	                HBox.setHgrow(name, Priority.ALWAYS);
531	
532	                Button open = new Button("Open folder");
533	                open.setStyle(
534	                    "-fx-background-color: transparent; -fx-border-color: rgba(76,217,123,0.4);" +
535	                    "-fx-border-width: 1; -fx-border-radius: 5; -fx-text-fill: #4cd97b;" +
536	                    "-fx-font-size: 11px; -fx-padding: 3 8 3 8; -fx-cursor: hand;"
537	                );
538	                open.setOnAction(e -> {
539	                    try {
540	                        java.awt.Desktop.getDesktop().open(p.getParent().toFile());
541	                    } catch (Exception ex) { /* Skip */ }
542	                });
543	
544	                row.getChildren().addAll(icon, name, open);
545	                resultBox.getChildren().add(row);
546	            }
547	        }
548	
549	        private void showError(Throwable err) {
550	            progressBar.setProgress(0);
551	            progressBar.setStyle(progressBar.getStyle().replace("#5b8cf7", "#f25c5c"));
552	            progressLabel.setText("❌ Split failed");
553	
554	            Label errLabel = new Label(err.getMessage());
555	            errLabel.setStyle(
556	                "-fx-text-fill: #f25c5c; -fx-font-size: 12px; -fx-wrap-text: true;" +
557	                "-fx-background-color: rgba(242,92,92,0.08); -fx-padding: 12;" +
558	                "-fx-background-radius: 8;"
559	            );
560	            errLabel.setWrapText(true);
561	            resultBox.getChildren().add(errLabel);
562	        }
563	    }
564	
565	    // ════════════════════════════════════════════════════
566	    // Shared UI tools
567	    // ════════════════════════════════════════════════════
568	
569	    private static Label sectionTitle(String text) {
570	        Label l = new Label(text);
571	        l.setStyle("-fx-text-fill: rgba(255,255,255,0.88); -fx-font-size: 15px; -fx-font-weight: 500;");
572	        return l;
