package fan.summer.buildintool.excelsplitter;

import java.nio.file.Path;
import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

public class SplitConfig {

    public enum SplitMode { SIMPLE, COMPLEX }
    public enum SimpleMode { BY_SHEET, BY_COLUMN }

    // Step 1: source file
    public Path sourceFile;

    // Populated by async analysis (sheet name -> col index -> header)
    public Map<String, Map<Integer, String>> analysisResult = new LinkedHashMap<>();

    // Step 2: mode
    public SplitMode mode = SplitMode.SIMPLE;

    // Simple mode
    public SimpleMode simpleMode = SimpleMode.BY_SHEET;
    public List<String> selectedSheets = new ArrayList<>();   // BY_SHEET: sheets to output
    public String selectedSheet;                               // BY_COLUMN: chosen sheet
    public int    selectedColumnIndex = -1;                    // BY_COLUMN: 0-based col idx

    // Complex mode
    public String taskId;   // "CSM-" + UUID, set when complex tab first entered

    // Step 3: output
    public Path outputDir;
}

