72	    private String i18n(String key) {
73	        return I18nManager.getPluginString("i18n.messages", key, getClass().getClassLoader());
74	    }
75	
76	    /**
77	     * Sets up global input listeners to detect human activity.
78	     * Expert mode: pause when human is moving, resume after 20s idle.
79	     */
80	    private void setupHumanInputDetection() {
81	        humanInputListener = new AWTEventListener() {
82	            @Override
83	            public void eventDispatched(AWTEvent event) {
84	                int id = event.getID();
85	                if (id == MouseEvent.MOUSE_MOVED ||
86	                        id == MouseEvent.MOUSE_DRAGGED ||
87	                        id == MouseEvent.MOUSE_PRESSED ||
88	                        id == MouseEvent.MOUSE_RELEASED ||
89	                        id == KeyEvent.KEY_PRESSED ||
90	                        id == KeyEvent.KEY_RELEASED) {
91	                    lastHumanInputTime = System.currentTimeMillis();
92	                }
93	            }
94	        };
95	        Toolkit.getDefaultToolkit().addAWTEventListener(
96	                humanInputListener,
97	                AWTEvent.MOUSE_MOTION_EVENT_MASK |
98	                        AWTEvent.MOUSE_EVENT_MASK |
99	                        AWTEvent.KEY_EVENT_MASK
100	        );
101	    }
102	
103	    /**
104	     * Checks if human has been idle for 20 seconds (resume condition).
105	     */
106	    private boolean isHumanIdle20Seconds() {
107	        return System.currentTimeMillis() - lastHumanInputTime >= 20_000;
108	    }
109	
110	    public JPanel getPanel() {
111	        return mouse;
112	    }
113	
114	    /**
115	     * Sets up action listeners for Start and Stop buttons.
116	     */
117	    private void setupEventHandlers() {
118	        // Start button - begins periodic mouse movement
119	        startMoveBt.addActionListener(new ActionListener() {
120	            @Override
121	            public void actionPerformed(ActionEvent e) {
122	                startMouseMove();
123	            }
124	        });
125	        // Stop button - stops periodic mouse movement
126	        stopMoveBt.addActionListener(new ActionListener() {
127	            @Override
128	            public void actionPerformed(ActionEvent e) {
129	                stopMouseMove();
130	            }
131	        });
132	    }
133	
134	    /**
135	     * Starts periodic mouse movement in expert mode.
136	     * Uses randomized intervals (15-45s) and movements (10-50px) to appear human-like
137	     * while ensuring any screensaver is prevented.
138	     */
139	    private void startMouseMove() {
140	        // Disable Start, enable Stop - button interlock
141	        startMoveBt.setEnabled(false);
142	        stopMoveBt.setEnabled(true);
143	
144	        timer = new Timer(true); // daemon timer
145	        // Schedule with expert mode: random interval to avoid pattern detection
146	        scheduleNextExpertMove();
147	    }
148	
149	    /**
150	     * Schedules the next expert mode move with randomized delay.
151	     */
152	    private void scheduleNextExpertMove() {
153	        if (timer == null) return;
154	
155	        // Random interval between 15-45 seconds (avoids screensaver pattern detection)
156	        int delay = EXPERT_MIN_INTERVAL_MS +
157	                random.nextInt(EXPERT_MAX_INTERVAL_MS - EXPERT_MIN_INTERVAL_MS);
158	
159	        timer.schedule(new TimerTask() {
160	            @Override
161	            public void run() {
162	                moveMouseExpert();
163	                scheduleNextExpertMove();
164	            }
165	        }, delay);
166	    }
167	
168	    /**
169	     * Stops the periodic mouse movement.
170	     */
171	    private void stopMouseMove() {
172	        if (timer != null) {
173	            timer.cancel();
174	            timer = null;
175	        }
176	        // Enable Start, disable Stop - button interlock
177	        startMoveBt.setEnabled(true);
178	        stopMoveBt.setEnabled(false);
179	    }
180	
181	    /**
182	     * Expert mode: Moves mouse with random offset and simulates human-like key activity.
183	     * Only runs when human has been idle for 20+ seconds.
184	     */
185	    private void moveMouseExpert() {
186	        // Only execute when human has been idle for 20 seconds
187	        if (!isHumanIdle20Seconds()) {
188	            return;
189	        }
190	
191	        Point location = MouseInfo.getPointerInfo().getLocation();
192	
193	        // Random movement distance (10-50 pixels) in random direction
194	        int moveDistance = EXPERT_MIN_MOVE +
195	                random.nextInt(EXPERT_MAX_MOVE - EXPERT_MIN_MOVE);
196	        int angle = random.nextInt(360);
197	        int dx = (int) (moveDistance * Math.cos(Math.toRadians(angle)));
198	        int dy = (int) (moveDistance * Math.sin(Math.toRadians(angle)));
199	
200	        robot.mouseMove((int) location.getX() + dx, (int) location.getY() + dy);
201	    }
